import java.io.IOException;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

// Import ESAPI classes for encoding
import org.owasp.esapi.ESAPI;
import org.owasp.esapi.Encoder;

public class XSSSecureCode {

    public void processInput(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");

        // Properly encoding user input using ESAPI Encoder
        Encoder encoder = ESAPI.encoder();
        String encodedUserInput = encoder.encodeForHTML(userInput);

        // Writing the HTML response with encoded user input
        response.getWriter().write("<html><body>User Input: " + encodedUserInput + "</body></html>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
